function __excelCtx(ctx){
  function doc(){ return ctx && ctx.$el ? ctx.$el.ownerDocument : document; }
  function visible(el){ if(!el) return false; var w=doc().defaultView||window; var s=w.getComputedStyle(el), r=el.getBoundingClientRect(); return s.display!=='none' && s.visibility!=='hidden' && r.width>0 && r.height>0; }
  function inputs(){ return Array.prototype.slice.call(doc().querySelectorAll('input,textarea')).filter(visible).filter(function(el){ return el.getBoundingClientRect().y < 230; }); }
  function inputValue(kind, fallback){
    var list=inputs();
    var el=null;
    if(kind==='addr') el=list.find(function(i){ return /cell address/i.test(i.placeholder||''); }) || list[0];
    if(kind==='value') el=list.find(function(i){ return /value to write/i.test(i.placeholder||''); }) || list[1];
    var v=el ? el.value : '';
    if(v===undefined || v===null || v==='') return fallback;
    return String(v).trim();
  }
  function report(){ var d=doc(); return d.querySelector('.page_report_view_container') && d.querySelector('.page_report_view_container').__vue__; }
  function sheetView(){ var d=doc(); return d.querySelector('.report-view-main') && d.querySelector('.report-view-main').__vue__; }
  function sheet(){ var vm=sheetView(); if(!vm || !vm.univerAPI) throw new Error('univerAPI not found'); return vm.univerAPI.getActiveWorkbook().getActiveSheet(); }
  function log(msg, detail){
    var sh=sheet();
    var r=sh.getRange('J1');
    r.setValue((new Date()).toLocaleTimeString() + ' ' + msg);
    try { r.setBackground('#fff7ed'); r.setFontColor('#9a3412'); r.setFontWeight('bold'); } catch(e) {}
    if(detail!==undefined){ var d=sh.getRange('J2'); d.setValue(String(detail)); try { d.setBackground('#f8fafc'); d.setFontColor('#111827'); } catch(e2) {} }
    window.__wos4ExcelLastAction={message:msg, detail:detail, at:new Date().toISOString()};
  }
  function normalizeAddress(addr){ addr=String(addr||'B1').trim().toUpperCase(); return /^[A-Z]+[1-9][0-9]*$/.test(addr) ? addr : 'B1'; }
  return {doc:doc, report:report, sheetView:sheetView, sheet:sheet, log:log, inputValue:inputValue, normalizeAddress:normalizeAddress};
}

