function __excelCtx(ctx){
  var kids = ctx && ctx.KMComponentsMng && ctx.KMComponentsMng.$Children ? ctx.KMComponentsMng.$Children : {};
  function pdOf(o){ return o && ((o._props && o._props.propData) || o.propData || o); }
  function objByName(name){
    if (kids[name]) return kids[name];
    var keys = Object.keys(kids || {});
    for (var i=0;i<keys.length;i++){
      var v=kids[keys[i]], pd=pdOf(v);
      if (pd && pd.UIName === name) return v;
      try { if (v && v.getObject) { var o=v.getObject(); if (o && o[0]) { var op=pdOf(o[0]); if (op && op.UIName===name) return o[0]; } } } catch(e) {}
    }
    return null;
  }
  function val(name, fallback){
    var c=objByName(name), pd=pdOf(c), v=pd && pd.value;
    if ((v===undefined || v===null || v==='') && c && c.$el) {
      var input=c.$el.querySelector('input,textarea');
      if (input) v=input.value;
    }
    if (v===undefined || v===null || v==='') return fallback;
    return String(v);
  }
  function doc(){ return ctx && ctx.$el ? ctx.$el.ownerDocument : document; }
  function report(){ var d=doc(); return d.querySelector('.page_report_view_container') && d.querySelector('.page_report_view_container').__vue__; }
  function sheetView(){ var d=doc(); return d.querySelector('.report-view-main') && d.querySelector('.report-view-main').__vue__; }
  function sheet(){ var vm=sheetView(); if(!vm || !vm.univerAPI) throw new Error('univerAPI not found'); return vm.univerAPI.getActiveWorkbook().getActiveSheet(); }
  function log(msg){
    var sh=sheet();
    var r=sh.getRange('J1');
    r.setValue((new Date()).toLocaleTimeString() + ' ' + msg);
    try { r.setBackground('#fff3bf'); r.setFontColor('#7c2d12'); r.setFontWeight('bold'); } catch(e) {}
    window.__wos4ExcelLastAction = { message: msg, at: new Date().toISOString() };
  }
  return {kids:kids, objByName:objByName, val:val, report:report, sheetView:sheetView, sheet:sheet, log:log};
}

